import{_ as l,r as t,o as i,c as r,a as n,b as e,e as s,d as o}from"./app-3aae6edf.js";const d={},c=o(`<h1 id="重建表优化空间与查询速度" tabindex="-1"><a class="header-anchor" href="#重建表优化空间与查询速度" aria-hidden="true">#</a> 重建表优化空间与查询速度</h1><p>当数据库运行一段时间后，服务器存储空间会越来越少。</p><p>此时我们仅仅删除数据是不够的。需要重建表才能减少表大小。</p><p>这是由于 InnoDB 里的数据都是用 B+ 树的结构组织的。删除某一个记录时候，仅仅标志为删除，后续可以复用。甚至来说，我们使用 delete 命令把整个表的数据删除时候，也不会增大磁盘的可用空间，仅仅会把所有的可用页面标志为可复用。</p><p>也就是说，通过 delete 命令是不能回收表空间的。而回收表空间需要对表进行重建。</p><p>而在 MySQL 5.6 之前的版本重建表需要执行下面语句。以下语句会先创建一张新表，不断的导入数据，最终删除原表，修改新的表名。但该语句执行过程中无法在进行表的写入。</p><div class="language-SQL line-numbers-mode" data-ext="SQL"><pre class="language-SQL"><code>alter table tbl_name engine=InnoDB
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>之后的版本开始引入的 Online DDL，可以在在线执行表的重建，原理是在拷贝的期间生成一个日志文件，方便拷贝完成后进行重放操作。</p><p>但还是要注意如果是在业务高峰的时候执行盖操作，很可能会造成日志过大，超过 innodb_online_alter_log_max_size 的限制。</p><p>语句如下所示：</p><div class="language-SQL line-numbers-mode" data-ext="SQL"><pre class="language-SQL"><code>ALTER TABLE tbl_name FORCE, ALGORITHM=INPLACE, LOCK=NONE;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用 ALGORITHM=COPY 则是 MySQL 5.6 之前的版本对应的操作。</p><p>需要注意的是： 无论是 INPLACE 还是 COPY 都需要更多的空间。所以我们应该尽量在早期进行表的优化，否则到了存储空间稀缺的情况，我们就没办法在进行表的重建了。</p><p>表重建也会增快表的查询速度，这是由于数据库“空洞“多了，要扫描的页越来越多导致的。</p><p>注意：单纯增加字段是不会导致锁表的，但是如果更改字段类型是会导致锁表的</p><p>如果表本省没有“空洞”，使用表重建反而会把表变大。</p><ul><li>在重建表的时，InnoDB 不会把整张表占满，每个页留了 1/16 给后续的更新用。</li><li>在DDL期间，如果刚好有外部的DML在执行，这期间可能会引入一些新的空洞。</li></ul>`,17),p={href:"https://github.com/github/gh-ost",target:"_blank",rel:"noopener noreferrer"};function u(_,h){const a=t("ExternalLinkIcon");return i(),r("div",null,[c,n("p",null,[e("如果需要较为安全的操作，可以学习使用 github 开发的 "),n("a",p,[e("gh-ost"),s(a)]),e(" 。")])])}const L=l(d,[["render",u],["__file","re-building.html.vue"]]);export{L as default};
